import React, { useEffect, useRef } from 'react';
import Phaser from 'phaser';

const BallyGamboyGame = () => {
  const gameRef = useRef(null);
  let player; // Define player object

  useEffect(() => {
    const initializeGame = () => {
      const config = {
        type: Phaser.AUTO,
        width: window.innerWidth, // Set width to match the window width
        height: window.innerHeight, // Set height to match the window height

        scene: {
          preload: preload,
          create: create,
          update: update,
        },
        scale: {
          mode: Phaser.Scale.RESIZE, // Resize the game to fill the entire screen
          autoCenter: Phaser.Scale.CENTER_BOTH, // Center the game horizontally and vertically
        },
      };

      gameRef.current = new Phaser.Game(config);
    };

    // Define scene methods
    function preload() {
      this.load.image('background', './phaser-resources/images/placeholders/gamboy.png');
      this.load.image('player', './phaser-resources/images/player.png'); // Load player image
    }

    function create(scene) {
      // Create the background sprite and set its size to match the game's canvas
      const background = scene.add.sprite(0, 0, 'background').setOrigin(0);
      background.displayWidth = scene.sys.game.config.width;
      background.displayHeight = scene.sys.game.config.height;

      // Create player character
      player = scene.physics.add.sprite(200, 200, 'player'); // Define player object
    }

    function update() {
      // Update game logic here
    }

    initializeGame();

    return () => {
      if (gameRef.current) {
        gameRef.current.destroy(true);
      }
    };
  }, []);

  return <div id="ballygamboy-game-container"></div>;
};

export default BallyGamboyGame;
